final:
module RefModule(
    input [3:0] data_in,
    input [1:0] select,
    output reg out
);
  wire [3:0] _tap_data_in = data_in & {4{1'b1}};


always @*
begin
    case (select)
        2'b00: out = data_in[0];
        2'b01: out = data_in[1];
        2'b10: out = data_in[2];
        2'b11: out = data_in[3];
        default: out = 0;
    endcase
end

endmodule
